        current_hcf = compute_hcf(current_window)
        if current_hcf >= 2:
            window_len = right - left + 1
            if window_len > 1:
                required_changes = 0
                for num in current_window:
                    if num % current_hcf != 0:
                        required_changes += 1
                if required_changes <= maxC:
                    min_stability = min(min_stability, window_len)
        else:
